import json
from decimal import Decimal, ROUND_HALF_UP

def validate_invoice(invoice):
    def round_2dp(value):
        return float(Decimal(str(value)).quantize(Decimal('0.01'), rounding=ROUND_HALF_UP))

    computed_subtotal = sum(item['quantity'] * item['unit_price'] for item in invoice['line_items'])
    computed_subtotal = round_2dp(computed_subtotal)

    computed_discount = computed_subtotal * invoice['discount_pct'] / 100
    computed_discount = round_2dp(computed_discount)

    computed_tax = (computed_subtotal - computed_discount) * invoice['tax_rate'] / 100
    computed_tax = round_2dp(computed_tax)

    computed_total = computed_subtotal - computed_discount + computed_tax + invoice['shipping']
    computed_total = round_2dp(computed_total)

    discrepancies = []

    if computed_subtotal != invoice['stated_subtotal']:
        discrepancies.append({
            'field': 'subtotal',
            'stated': invoice['stated_subtotal'],
            'computed': computed_subtotal,
            'delta': round_2dp(computed_subtotal - invoice['stated_subtotal'])
        })

    if computed_discount != invoice['stated_discount']:
        discrepancies.append({
            'field': 'discount',
            'stated': invoice['stated_discount'],
            'computed': computed_discount,
            'delta': round_2dp(computed_discount - invoice['stated_discount'])
        })

    if computed_tax != invoice['stated_tax']:
        discrepancies.append({
            'field': 'tax',
            'stated': invoice['stated_tax'],
            'computed': computed_tax,
            'delta': round_2dp(computed_tax - invoice['stated_tax'])
        })

    if computed_total != invoice['stated_total']:
        discrepancies.append({
            'field': 'total',
            'stated': invoice['stated_total'],
            'computed': computed_total,
            'delta': round_2dp(computed_total - invoice['stated_total'])
        })

    return {
        'invoice_id': invoice['invoice_id'],
        'vendor': invoice['vendor'],
        'computed': {
            'subtotal': computed_subtotal,
            'discount': computed_discount,
            'tax': computed_tax,
            'total': computed_total
        },
        'discrepancies': discrepancies,
        'valid': len(discrepancies) == 0
    }

with open('sample_inputs/invoice_002.json', 'r') as f:
    invoice = json.load(f)

result = validate_invoice(invoice)

with open('output.json', 'w') as f:
    json.dump(result, f, indent=2)

print("Invoice BC-9920-A: VALID" if result['valid'] else "Invoice BC-9920-A: INVALID")
